int count_pairs_summing(const std::vector<int>& nums, int target){
    std::map<int,int> seen;
    int count = 0;
    for (size_t i = 0; i < nums.size(); ++i){
        int need = target - nums[i];
        std::map<int,int>::iterator it = seen.find(need);
        if (it != seen.end()) count += it->second;
        seen[nums[i]] += 1;
    }
    return count;
}

