    std::map<int,int> in_a;
    for (size_t i = 0; i < a.size(); ++i) in_a[a[i]] = 1;
    std::map<int,int> counted;
    int result = 0;
    for (size_t i = 0; i < b.size(); ++i){
        if (in_a.find(b[i]) != in_a.end() && counted.find(b[i]) == counted.end()){
