def sorted_key(w: String) -> String:
    var counts = InlineArray[Int, 26](fill=0)
    for cp in w.codepoints():
        var c = Int(cp)
        if c >= 97 and c <= 122:
            counts[c - 97] += 1
    var result = String("")
    for i in range(26):
        for _ in range(counts[i]):
            result += chr(97 + i)
    return result

def anagram_groups_count(words: List[String]) raises -> Int:
    var groups = Dict[String, Int]()
    for i in range(len(words)):
        var key = sorted_key(words[i])
        if key in groups:
            groups[key] = groups[key] + 1
        else:
            groups[key] = 1
    return len(groups)

